Vtiger_Detail_Js("HelpDesk_Detail_Js",{setAccountsReference:function(){var e={module:"Accounts",view:"Popup",src_module:"HelpDesk",src_record:app.getRecordId()};Vtiger_Popup_Js.getInstance().show(e,function(e){var t=JSON.parse(e);$.each(t,function(e,t){Vtiger_Detail_Js.getInstance().saveFieldValues({field:"parent_id",value:e}).then(function(e){location.reload()})})})}},{registerSetServiceContracts:function(){var e=this;$(".selectServiceContracts").on("click","ul li",function(t){var i=jQuery(t.currentTarget);e.saveFieldValues({field:"servicecontractsid",value:i.data("id")}).then(function(e){location.reload()})})},registerEvents:function(){this._super(),this.registerSetServiceContracts()}});